export default function SponsorMarquee({ dark }) {
  var bg     = dark ? "rgba(255,255,255,0.02)" : "rgba(122,63,209,0.02)";
  var border = dark ? "rgba(155,135,245,0.10)" : "rgba(122,63,209,0.08)";
  var fade   = dark ? "#06020f" : "#ffffff";
  var items  = [...SPONSORS, ...SPONSORS];

  
  return (
    <section
      style={{
        background: bg,
        borderTop: "1px solid " + border,
        borderBottom: "1px solid " + border,
        padding: "32px 0 28px",
        overflow: "hidden",
        position: "relative",
      }}
    >
      <style>{`
        @keyframes marquee-scroll {
          0%   { transform: translateX(0); }
          100% { transform: translateX(-50%); }
        }
        .marquee-track {
          display: flex;
          width: max-content;
          animation: marquee-scroll 32s linear infinite;
        }
        .marquee-track:hover { animation-play-state: paused; }
        .marquee-item {
          display: flex;
          align-items: center;
          justify-content: center;
          padding: 0 44px;
          border-right: 1px solid ${border};
          height: 60px;
          flex-shrink: 0;
        }
        .marquee-item img {
          height: 40px;
          width: auto;
          max-width: 180px;
          object-fit: contain;
          opacity: ${dark ? "0.90" : "0.70"};
          filter: ${dark ? "brightness(0) invert(1)" : "none"};
          transition: opacity 0.2s ease;
        }
        .marquee-item:hover img {
          opacity: ${dark ? "1" : "1"};
        }
        .marquee-item img[data-name="Temasek"]   { height: 17px; }
        .marquee-item img[data-name="Amazon"]    { height: 26px; }
        .marquee-item img[data-name="DHL"]       { height: 58px; }
        .marquee-item img[data-name="Constellar"]{ height: 50px; }
        .marquee-item img[data-name="Ford"]      { height: 50px; }
        .marquee-item img[data-name="KPMG"]      { height: 46px; }
        .marquee-item img[data-name="Accenture"] { height: 26px; }
        .marquee-item img[data-name="Cvent"]    { height: 26px; filter: none !important; opacity: 0.7 !important; }
        .marquee-item img[data-name="VMware"]    { height: 54px; }
      `}</style>

      <div
        style={{
          textAlign: "center",
          marginBottom: 18,
          fontFamily: "'Orbitron',sans-serif",
          fontSize: "0.6rem",
          fontWeight: 700,
          letterSpacing: "2px",
          textTransform: "uppercase",
          color: dark ? "rgba(200,185,255,0.40)" : "rgba(13,5,32,0.35)",
        }}
      >
        Our team includes alumni from
      </div>

      <div style={{ position: "relative" }}>
        <div style={{ position: "absolute", left: 0, top: 0, bottom: 0, width: 100, background: `linear-gradient(to right, ${fade}, transparent)`, zIndex: 2, pointerEvents: "none" }} />
        <div style={{ position: "absolute", right: 0, top: 0, bottom: 0, width: 100, background: `linear-gradient(to left, ${fade}, transparent)`, zIndex: 2, pointerEvents: "none" }} />
        <div className="marquee-track">
          {items.map(function (s, i) {
            return (
              <div key={i} className="marquee-item">
                <img src={s.logo} alt={s.name} title={s.name} data-name={s.name} />
              </div>
            );
          })}
        </div>
      </div>
    </section>
  );
}
